# 2. FILTER_TEXT_TWEETS
# ============================================================================

#' Filter out media-only tweets
#'
#' Removes tweets that contain only media (images/videos) with no text content.
#' Keeps tweets that have text, even if they also contain media.
#'
#' @param posts_tibble Tibble from fetch_posts_by_date_range()
#'
#' @return Filtered tibble containing only text tweets (is_media_only == FALSE)
#'
#' @examples
#' \dontrun{
#'   posts <- fetch_posts_by_date_range("2026-05-01", "2026-05-04")
#'   text_tweets <- filter_text_tweets(posts)
#' }
#'
#' @export
filter_text_tweets <- function(posts_tibble) {
  posts_tibble |>
    dplyr::filter(!is_media_only)
}

# ============================================================================
# 3. SORT_CHRONOLOGICAL
# ============================================================================

#' Sort tweets in chronological order
#'
#' Sorts the tweet tibble by date_time, with oldest posts first (ascending).
#'
#' @param posts_tibble Tibble with date_time column
#' @param oldest_first Logical. If TRUE (default), sorts ascending (oldest first).
#'   If FALSE, sorts descending (newest first).
#'
#' @return Tibble sorted by date_time
#'
#' @examples
#' \dontrun{
#'   posts <- fetch_posts_by_date_range("2026-05-01", "2026-05-04")
#'   text_tweets <- filter_text_tweets(posts)
#'   sorted_posts <- sort_chronological(text_tweets)
#' }
#'
#' @export
sort_chronological <- function(posts_tibble, oldest_first = TRUE) {
  if (oldest_first) {
    posts_tibble |>
      dplyr::arrange(date_time)
  } else {
    posts_tibble |>
      dplyr::arrange(dplyr::desc(date_time))
  }
}

