# 4. FORMAT_OUTPUT
# ============================================================================

#' Format tweets for text file output
#'
#' Converts the sorted posts tibble into a character vector suitable for
#' writing to a .txt file.
#'
#' @param posts_tibble Tibble with date_time and text columns (already sorted)
#' @param include_date_headers Logical. If TRUE, includes date headers
#'   (one header per date). Default is FALSE (one tweet per line).
#'
#' @return Character vector where each element is a tweet (or header, if enabled)
#'
#' @details
#' Default format (include_date_headers = FALSE):
#'   - One tweet per line
#'   - Tweets separated by blank lines
#'   - No headers
#'
#' With headers (include_date_headers = TRUE):
#'   - Group tweets by date
#'   - Add "--- YYYY-MM-DD ---" header before each date's tweets
#'   - One tweet per line within each group
#'
#' @examples
#' \dontrun{
#'   posts <- fetch_posts_by_date_range("2026-05-01", "2026-05-04")
#'   text_tweets <- filter_text_tweets(posts)
#'   sorted_posts <- sort_chronological(text_tweets)
#'   formatted <- format_output(sorted_posts, include_date_headers = FALSE)
#' }
#'
#' @export
format_output <- function(posts_tibble, include_date_headers = FALSE) {
  if (nrow(posts_tibble) == 0) {
    return(character(0))
  }

  if (!include_date_headers) {
    # Simple format: one tweet per line with blank line separator
    tweets <- posts_tibble$text
    # Alternate tweets with blank lines
    output <- character(length(tweets) * 2 - 1)
    output[seq(1, length(tweets) * 2 - 1, 2)] <- tweets
    output[seq(2, length(tweets) * 2 - 1, 2)] <- ""
    return(output)
  } else {
    # Format with date headers
    posts_tibble <- posts_tibble |>
      dplyr::mutate(
        date_only = lubridate::date(date_time)
      )

    output <- character()

    current_date <- NULL
    for (i in seq_len(nrow(posts_tibble))) {
      row <- posts_tibble[i, ]
      row_date <- row$date_only[[1]]

      # Add date header if date changed
      if (is.null(current_date) || row_date != current_date) {
        output <- c(output, sprintf("--- %s ---", row_date))
        current_date <- row_date
      }

      # Add tweet
      output <- c(output, row$text[[1]])
      # Add blank line
      output <- c(output, "")
    }

    return(output)
  }
}

