# ============================================================================

#' Scrape Trump's Truth Social tweets and save to file
#'
#' Main function that orchestrates the entire pipeline: fetch posts,
#' filter media-only tweets, sort chronologically, format, and save to file.
#'
#' @param start_date Date or character. Start date (YYYY-MM-DD format)
#' @param end_date Date or character. End date (YYYY-MM-DD format)
#' @param output_filename Character. Output .txt filename (default: "tweets.txt")
#' @param include_date_headers Logical. Include date headers in output
#'   (default: FALSE)
#' @param posts_per_page Numeric. Posts per page (default: 100)
#'
#' @return Invisibly returns the output file path. As a side effect, prints
#'   a summary of the scraping operation and saves tweets to file.
#'
#' @details
#' This is the main user-facing function. It chains together all modular
#' functions in the correct order and provides informative logging.
#'
#' Summary printed includes:
#' - Total posts fetched
#' - Posts filtered (media-only)
#' - Text posts kept
#' - Date range of output
#' - Output file location
#'
#' @examples
#' \dontrun{
#'   # Scrape tweets from May 1-4, 2026
#'   scrape_truth_social_tweets(
#'     start_date = "2026-05-01",
#'     end_date = "2026-05-04",
#'     output_filename = "may_tweets.txt"
#'   )
#'
#'   # Scrape with date headers
#'   scrape_truth_social_tweets(
#'     start_date = "2026-05-01",
#'     end_date = "2026-05-04",
#'     include_date_headers = TRUE
#'   )
#' }
#'
#' @export
scrape_truth_social_tweets <- function(start_date,
                                        end_date,
                                        output_filename = "tweets.txt",
                                        include_date_headers = FALSE,
                                        posts_per_page = 100) {

  message("\n========== TRUMP'S TRUTH SOCIAL SCRAPER ==========\n")

  # Fetch posts
  all_posts <- fetch_posts_by_date_range(
    start_date,
    end_date,
    posts_per_page
  )

  if (nrow(all_posts) == 0) {
    message("No posts found in the specified date range.")
    return(invisible(NULL))
  }

  # Count media-only
  media_only_count <- sum(all_posts$is_media_only, na.rm = TRUE)

  # Filter text tweets
  text_posts <- filter_text_tweets(all_posts)

  message(sprintf(
    "Filtered: %d media-only tweets removed, %d text tweets retained",
    media_only_count,
    nrow(text_posts)
  ))

  # Sort chronologically (oldest first)
  sorted_posts <- sort_chronological(text_posts, oldest_first = TRUE)

  # Format output
  formatted <- format_output(sorted_posts, include_date_headers)

  # Save to file
  output_path <- save_tweets_to_file(formatted, output_filename)

  # Print summary
  date_range <- sprintf(
    "%s to %s",
    min(sorted_posts$date_time, na.rm = TRUE),
    max(sorted_posts$date_time, na.rm = TRUE)
  )

  message("\n========== SUMMARY ==========")
  message(sprintf("Total posts fetched: %d", nrow(all_posts)))
  message(sprintf("Media-only tweets filtered: %d", media_only_count))
  message(sprintf("Text tweets in output: %d", nrow(text_posts)))
  message(sprintf("Date range (output): %s", date_range))
  message(sprintf("Output file: %s", output_filename))
  message("=============================\n")

  invisible(output_path)
}

